// // This module implements a 4-bit register that loads new data on the falling edge of the clock when the enable signal is low and resets to 1 on the reset signal.
module reg_with_enable(
    input clk,
    input reset,
    input enable,
    input [3:0] d,
    output reg [3:0] q
    );

    always @(posedge clk) begin
        if (reset)
            q <= 4'b0000;
        else if (enable)
            q <= d;
    end
endmodule
